  wd:Q23816082 wdt:P710 ?athlete .
  {
    wd:Q11900438 wdt:P1346 ?athlete .
    BIND("gold" AS ?medal)
  } UNION {
    wd:Q11900438 wdt:P1345 ?athlete .
    BIND("silver" AS ?medal)
  } UNION {
    wd:Q11900438 wdt:P1344 ?athlete .
    BIND("bronze" AS ?medal)
  }
}
